23	type ScenarioOutput = {
24	  results: unknown[];
25	};
26	
27	const PROCESSING_FEE = 5;
28	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
29	const CURSE_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_THRESHOLD = 5;
31	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
32	const LOYALTY_YEARS_THRESHOLD = 2;
33	const LOYALTY_DISCOUNT_RATE = 0.2;
34	const COMPONENT_BLOCK_SIZE = 3;
35	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
36	
37	const BASE_PREMIUMS: Record<string, number> = {
38	  sword: 100,
39	  amulet: 60,
40	  staff: 80,
41	  potion: 40,
42	  rune: 25,
43	  moonstone: 25,
44	};
45	
46	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
47	
48	const isComponentBlock = (type: string, count: number): boolean =>
49	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
50	
51	const surchargeFor = (
52	  items: Item[],
53	  applies: (item: Item) => boolean,
54	  rate: number
55	): number =>
56	  items.reduce(
57	    (surcharge, item) =>
58	      applies(item) ? surcharge + BASE_PREMIUMS[item.type] * rate : surcharge,
59	    0
60	  );
61	
62	const isCursed = (item: Item): boolean => item.cursed === true;
63	
64	const isHighlyEnchanted = (item: Item): boolean =>
65	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
66	
67	const curseSurchargeFor = (items: Item[]): number =>
68	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
69	
70	const enchantmentSurchargeFor = (items: Item[]): number =>
71	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
72	
73	const basePremiumFor = (items: Item[]): number => {
74	  const countsByType = new Map<string, number>();
75	  for (const item of items) {
76	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
77	  }
78	
79	  let basePremium = curseSurchargeFor(items) + enchantmentSurchargeFor(items);
80	  for (const [type, count] of countsByType) {
81	    basePremium += isComponentBlock(type, count)
82	      ? COMPONENT_BLOCK_BASE_PREMIUM
83	      : count * BASE_PREMIUMS[type];
84	  }
85	  return basePremium;
86	};
87	
88	const quotePremium = (items: Item[], customer: Customer): number => {
89	  const basePremium = basePremiumFor(items);
90	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
91	  const loyaltyDiscount =
92	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
93	      ? basePremium * LOYALTY_DISCOUNT_RATE
94	      : 0;
95	  return Math.ceil(
96	    basePremium + firstInsuranceSurcharge - loyaltyDiscount + PROCESSING_FEE
97	  );
98	};
99	
100	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
101	  const items = input.steps[0].items ?? [];
102	  return { results: [{ premium: quotePremium(items, input.customer) }] };
103	};
